INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Foi treinado em containers e orquestração, aplica utilizando documentação oficial e padrões já definidos. Consegue criar e gerenciar containers Docker, realizar deploy em Kubernetes (ou outro orquestrador) e operar ambientes existentes com autonomia operacional. Utiliza automações e pipelines já estruturados, entende os principais conceitos como imagem, container, registry, pods, services e deployments. Realiza troubleshooting básico por meio de análise de logs e status dos recursos e consegue gerenciar casos intermediários envolvendo variáveis, volumes, redes e secrets.' FROM skills s, roles r WHERE s.name = 'Containers, Orquestração e Nuvem' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Foi acompanhado e validado na execução de ambientes containerizados, sendo capaz de identificar falhas, problemas de performance e oportunidades de melhoria. Atua na criação de novos ambientes e arquiteturas, identifica gaps de FinOps relacionados a custos de cluster e recursos superdimensionados. Domina Helm, YAML avançado e estratégias de deploy como rolling update, blue/green e canary. Propõe melhorias em arquitetura de nuvem, rede, builds e processos DevOps, aplicando boas práticas de segurança, escalabilidade e alta disponibilidade. Executa troubleshooting avançado e atua com visão crítica sobre eficiência e resiliência da solução.' FROM skills s, roles r WHERE s.name = 'Containers, Orquestração e Nuvem' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'É referência técnica em containers e orquestração, possuindo domínio não apenas operacional, mas também estratégico dos conceitos de mercado que envolvem cloud native, microserviços, arquitetura distribuída e SRE. Tem capacidade de treinar e formar outros profissionais, definir padrões e governança para uso de containers na organização e conduzir decisões arquiteturais de alto impacto. Atua na definição de estratégias multi-cloud ou híbridas, otimização estruturada de custos (FinOps), segurança da cadeia de build e observabilidade. Influencia a maturidade técnica do time e estabelece direcionamento estratégico para a evolução do ecossistema de containers.' FROM skills s, roles r WHERE s.name = 'Containers, Orquestração e Nuvem' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
