INSERT INTO skill_expectations (skill_id, role_id, grade_id, expected_level, is_required) SELECT s.id, r.id, g.id, 'OURO', TRUE FROM skills s, roles r, grades g WHERE s.name = 'Segurança / Sonar / Dojo / Dependency Track / Dependency Check / NDE' AND r.name = 'DevOps' AND g.name = 'SENIOR' ON CONFLICT (skill_id, role_id, grade_id) DO UPDATE SET expected_level = EXCLUDED.expected_level, is_required = EXCLUDED.is_required;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Foi treinado nos conceitos básicos de segurança de aplicação e conhece as ferramentas utilizadas no ecossistema, como Sonar, Dojo, Dependency Track, Dependency Check e NDE. Entende onde essas ferramentas são configuradas, qual o papel de cada uma no processo de segurança e quem são os responsáveis por cada frente. Consegue acompanhar relatórios e identificar pontos gerais de atenção, mesmo que ainda sem domínio técnico aprofundado. Sabe articular conversas com os times responsáveis, envolver os donos corretos e contribuir para que os objetivos estratégicos de segurança sejam atendidos. Atua seguindo processos estabelecidos e compreendendo a importância da segurança no ciclo de desenvolvimento.' FROM skills s, roles r WHERE s.name = 'Segurança / Sonar / Dojo / Dependency Track / Dependency Check / NDE' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Aplica as ferramentas de segurança com autonomia e domínio técnico, configurando corretamente builds, pipelines e integrações. Interpreta relatórios de vulnerabilidade, qualidade de código e dependências, apoiando ativamente o time de desenvolvimento na correção e priorização de riscos. Participa de discussões técnicas de segurança com protagonismo, sustentando argumentos técnicos e propondo melhorias. Cria automações de segurança, integrações entre ferramentas e relatórios executivos que ampliam a visibilidade dos riscos. Atua de forma preventiva, promovendo boas práticas de secure coding, gestão de vulnerabilidades e governança de dependências, garantindo aderência às diretrizes organizacionais.' FROM skills s, roles r WHERE s.name = 'Segurança / Sonar / Dojo / Dependency Track / Dependency Check / NDE' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Atua como referência e pilar estratégico de segurança, exercendo papel de Security Champion (stackholder ativo da segurança) na organização. Envolve-se em metas, discussões de alto nível e definições estruturais relacionadas à governança, maturidade e evolução da segurança. Participa da tomada de decisão sobre ferramentas, processos e arquitetura de segurança, garantindo alinhamento com práticas de mercado como DevSecOps e Shift Left Security. É fomentador do tema dentro da organização, promovendo cultura de segurança, capacitação contínua e integração entre times. Atua como elo entre estratégia e execução, apoiando áreas técnicas e liderança na construção de um ecossistema seguro, sustentável e escalável.' FROM skills s, roles r WHERE s.name = 'Segurança / Sonar / Dojo / Dependency Track / Dependency Check / NDE' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
