INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Escreve scripts mais complexos para automatizar processos de infraestrutura, como configurações de servidores, provisionamento de ambientes, ou integração entre ferramentas.
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Desenvolve scripts avançados para automação de infraestrutura em larga escala, aplicando melhores práticas de modularidade, reutilização de código e otimização de desempenho.
