INSERT INTO skill_expectations (skill_id, role_id, grade_id, expected_level, is_required) SELECT s.id, r.id, g.id, 'PRATA', TRUE FROM skills s, roles r, grades g WHERE s.name = 'Topologia do sistema' AND r.name = 'DevOps' AND g.name = 'PLENO' ON CONFLICT (skill_id, role_id, grade_id) DO UPDATE SET expected_level = EXCLUDED.expected_level, is_required = EXCLUDED.is_required;
INSERT INTO skill_expectations (skill_id, role_id, grade_id, expected_level, is_required) SELECT s.id, r.id, g.id, 'OURO', TRUE FROM skills s, roles r, grades g WHERE s.name = 'Topologia do sistema' AND r.name = 'DevOps' AND g.name = 'SENIOR' ON CONFLICT (skill_id, role_id, grade_id) DO UPDATE SET expected_level = EXCLUDED.expected_level, is_required = EXCLUDED.is_required;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Foi treinado na topologia do sistema e entende, na prática, como ocorre a comunicação entre os módulos, incluindo banco de dados, mensageria (RabbitMQ), chamadas REST e integrações internas. Compreende como os módulos são divididos por criticidade, identificando módulos críticos e secundários, bem como suas dependências. Consegue aplicar corretamente essas dependências em ambientes já estruturados e analisar de forma crítica anomalias básicas na topologia, como módulos duplicados sem necessidade, configurações excessivas ou inconsistências evidentes. Atua seguindo o desenho arquitetural já definido, compreendendo o fluxo sistêmico da aplicação.' FROM skills s, roles r WHERE s.name = 'Topologia do sistema' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Domina os parâmetros técnicos que envolvem topologia, rede, filas (RabbitMQ), banco de dados e integrações entre módulos. Identifica gargalos de performance e pontos críticos de comunicação, atuando diretamente na otimização de filas, conexões, tempo de resposta e consumo de recursos. Apoia de forma crítica o time de SRE em incidentes relacionados a lentidão, erros de comunicação, falhas de integração e configurações inadequadas. Atua com visão analítica sobre impacto sistêmico, propondo melhorias estruturais na topologia e prevenindo problemas recorrentes. Treina e capacita outras pessoas com segurança técnica, assumindo responsabilidade prática sobre a topologia e seu correto funcionamento.' FROM skills s, roles r WHERE s.name = 'Topologia do sistema' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Possui domínio técnico suficiente para identificar riscos ocultos, problemas de performance, falhas de modelagem, violações de padrões e potenciais regressões. Consegue antecipar cenários de erro, questionar decisões arquiteturais e sugerir melhorias estruturais, não apenas ajustes pontuais. Além disso, atua como guardião da qualidade e da cultura técnica do time. Seus feedbacks são claros, objetivos e didáticos, diferenciando criticidade de sugestão. Ele contribui para evolução coletiva, fortalece padrões acordados e eleva o nível das entregas a cada revisão.' FROM skills s, roles r WHERE s.name = 'Topologia do sistema' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
