INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Possui compreensão teórica e prática sobre o padrão de versionamento vigente na organização. É capaz de executar pipelines de build para componentes garantindo o uso das versões corretas e compreende a aplicação de versões genéricas (ex: 3.0.*) para facilitar atualizações menores. Entende os conceitos de Release Candidate (RC) e possui autonomia para rodar releases de hosts atualizados no TFS. Utiliza referências de pacotes NuGet seguindo os padrões estabelecidos, garantindo que as dependências estejam alinhadas ao ambiente de desenvolvimento.' FROM skills s, roles r WHERE s.name = 'Configuração de Builds e Versionamento de Componetes / Nuget' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Atua ativamente na manutenção e evolução das pipelines de build e release dos componentes. Possui domínio técnico para alterar scripts de integração contínua, garantindo a integridade dos artefatos gerados. Aplica as boas práticas de componentização no dia a dia, evitando acoplamentos desnecessários e garantindo a retrocompatibilidade. Conhece o ecossistema de componentes internos da empresa, sendo capaz de identificar qual biblioteca deve ser utilizada ou atualizada para atender a uma nova demanda técnica.' FROM skills s, roles r WHERE s.name = 'Configuração de Builds e Versionamento de Componetes / Nuget' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Atua como guardião das boas práticas de componentização e versionamento na organização. Possui visão estratégica para decidir sobre a granularidade dos pacotes, determinando com precisão o momento necessário para a criação de um novo componente versus a evolução de um existente. Dissemina conhecimento técnico, mentorando o time na resolução de conflitos de dependências complexas e na otimização do ciclo de vida dos artefatos. Define padrões de governança para o feed de NuGet, estratégias de branching para componentes e assegura que a arquitetura de software permaneça modular, escalável e de fácil manutenção.' FROM skills s, roles r WHERE s.name = 'Configuração de Builds e Versionamento de Componetes / Nuget' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Possui compreensão teórica e prática sobre o padrão de versionamento vigente na organização. É capaz de executar pipelines de build para componentes garantindo o uso das versões corretas e compreende a aplicação de versões genéricas (ex: 3.0.*) para facilitar atualizações menores. Entende os conceitos de Release Candidate (RC) e possui autonomia para rodar releases de hosts atualizados no TFS. Utiliza referências de pacotes NuGet seguindo os padrões estabelecidos, garantindo que as dependências estejam alinhadas ao ambiente de desenvolvimento.' FROM skills s, roles r WHERE s.name = 'Configuração de Builds e Versionamento de Componetes / Nuget' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Atua ativamente na manutenção e evolução das pipelines de build e release dos componentes. Possui domínio técnico para alterar scripts de integração contínua, garantindo a integridade dos artefatos gerados. Aplica as boas práticas de componentização no dia a dia, evitando acoplamentos desnecessários e garantindo a retrocompatibilidade. Conhece o ecossistema de componentes internos da empresa, sendo capaz de identificar qual biblioteca deve ser utilizada ou atualizada para atender a uma nova demanda técnica.' FROM skills s, roles r WHERE s.name = 'Configuração de Builds e Versionamento de Componetes / Nuget' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Atua como guardião das boas práticas de componentização e versionamento na organização. Possui visão estratégica para decidir sobre a granularidade dos pacotes, determinando com precisão o momento necessário para a criação de um novo componente versus a evolução de um existente. Dissemina conhecimento técnico, mentorando o time na resolução de conflitos de dependências complexas e na otimização do ciclo de vida dos artefatos. Define padrões de governança para o feed de NuGet, estratégias de branching para componentes e assegura que a arquitetura de software permaneça modular, escalável e de fácil manutenção.' FROM skills s, roles r WHERE s.name = 'Configuração de Builds e Versionamento de Componetes / Nuget' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Possui compreensão teórica e prática sobre o padrão de versionamento vigente na organização. É capaz de executar pipelines de build para componentes garantindo o uso das versões corretas e compreende a aplicação de versões genéricas (ex: 3.0.*) para facilitar atualizações menores. Entende os conceitos de Release Candidate (RC) e possui autonomia para rodar releases de hosts atualizados no TFS. Utiliza referências de pacotes NuGet seguindo os padrões estabelecidos, garantindo que as dependências estejam alinhadas ao ambiente de desenvolvimento.' FROM skills s, roles r WHERE s.name = 'Configuração de Builds e Versionamento de Componetes / Nuget' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Atua ativamente na manutenção e evolução das pipelines de build e release dos componentes. Possui domínio técnico para alterar scripts de integração contínua, garantindo a integridade dos artefatos gerados. Aplica as boas práticas de componentização no dia a dia, evitando acoplamentos desnecessários e garantindo a retrocompatibilidade. Conhece o ecossistema de componentes internos da empresa, sendo capaz de identificar qual biblioteca deve ser utilizada ou atualizada para atender a uma nova demanda técnica.' FROM skills s, roles r WHERE s.name = 'Configuração de Builds e Versionamento de Componetes / Nuget' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Atua como guardião das boas práticas de componentização e versionamento na organização. Possui visão estratégica para decidir sobre a granularidade dos pacotes, determinando com precisão o momento necessário para a criação de um novo componente versus a evolução de um existente. Dissemina conhecimento técnico, mentorando o time na resolução de conflitos de dependências complexas e na otimização do ciclo de vida dos artefatos. Define padrões de governança para o feed de NuGet, estratégias de branching para componentes e assegura que a arquitetura de software permaneça modular, escalável e de fácil manutenção.' FROM skills s, roles r WHERE s.name = 'Configuração de Builds e Versionamento de Componetes / Nuget' AND r.name = 'DevOps' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
