INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Dev: Compreende a importância da documentação técnica e dos diagramas (fluxogramas, UML) para o entendimento e a comunicação dos processos de backend. Consegue gerar documentação simples, descrevendo APIs, fluxos de dados e integrações com outros sistemas. Tem conhecimento básico de como usar o APIARY para documentar APIs, incluindo descrição de endpoints e parâmetros de forma funcional, mas pode precisar de ajuda para situações mais complexas.
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Dev: Gera documentação técnica detalhada para sistemas, incluindo fluxogramas e diagramas UML para descrever os processos e interações do sistema.
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Dev: É expert na documentação técnica, criando diagramas UML e fluxogramas complexos que detalham a arquitetura do sistema, componentes e fluxos de dados.
