INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Foi treinado ou estudou a documentação oficial da API Cadastro e compreende sua visão de produto como solução de cadastro e ativação automatizada de empresas, incluindo também cadastro e configuração de documentos fiscais. Compreende a arquitetura geral da API e sua jornada de utilização, a obrigatoriedade de que todas as chamadas partam de um Parceiro, utilizando client e secret válidos para obtenção do IdContrato. A sequência lógica das chamadas (Autenticação, Licenças, Integrações, Cadastro de Empresa, Documentos fiscais etc.), a utilização do repositório ndd-configuracao e o uso do Template API. Possui entendimento conceitual dos endpoints (CTe, MDFe, NFe, NFSe, e-mails, integrações, campos específicos), mas ainda não executa implementações ou manutenções diretamente.' FROM skills s, roles r WHERE s.name = 'API Cadastro' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Possui conhecimento prático da API Cadastro, realizando implementações e manutenções com autonomia moderada. É capaz de configurar e testar autenticação via Bearer Token entendendo a obrigatoriedade de que todas as chamadas partam de um Parceiro, utilizando client e secret válidos para obtenção do IdContrato. Executar a jornada completa de ativação de empresa via API. Implementa e valida chamadas garantindo retorno adequado no formato esperado. Capaz de criar e/ou manter endpoints seguindo o padrão do repositório ndd-configuracao. Compreende o cadastro e validações de documentos fiscais (CTe, MDFe, NFe, NFSe – emissão e recebimento). Consegue identificar e corrigir erros comuns de autenticação, integração ou inconsistência de dados e é capaz de validar corretamente vínculo com Parceiro e captura de IdContrato. Atua na sustentação da API, realizando manutenção de nível básico a intermediário, seguindo padrões estabelecidos e boas práticas da equipe.' FROM skills s, roles r WHERE s.name = 'API Cadastro' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Possui conhecimento avançado e visão sistêmica da API Cadastro, atuando como referência técnica na solução. É capaz de definir e evoluir padrões arquiteturais da API. Projetar melhorias estruturais visando escalabilidade, segurança e performance. Atuar em decisões técnicas sobre autenticação, versionamento e integração entre APIs. Otimizar consultas com dapper e estrutura de dados na base Central_frontConfig. Analisar impactos de mudanças na jornada de ativação de empresas. Atuar preventivamente em segurança (tokens, autorização, validação de dados). onhecimento para análise de incidentes críticos. Apoiar integrações complexas com parceiros e novos fluxos de ativação. Treinar e desenvolver outros profissionais na utilização e evolução da API. Atua estrategicamente na evolução da API Cadastro, garantindo robustez, governança técnica, alinhamento arquitetural e sustentabilidade da solução no longo prazo. Capaz de planejar e criar novos cadastros para documentos que ainda não fazem parte da API Cadastro.' FROM skills s, roles r WHERE s.name = 'API Cadastro' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Foi treinado ou estudou a documentação oficial da API Cadastro e compreende sua visão de produto como solução de cadastro e ativação automatizada de empresas, incluindo também cadastro e configuração de documentos fiscais. Compreende a arquitetura geral da API e sua jornada de utilização, a obrigatoriedade de que todas as chamadas partam de um Parceiro, utilizando client e secret válidos para obtenção do IdContrato. A sequência lógica das chamadas (Autenticação, Licenças, Integrações, Cadastro de Empresa, Documentos fiscais etc.), a utilização do repositório ndd-configuracao e o uso do Template API. Possui entendimento conceitual dos endpoints (CTe, MDFe, NFe, NFSe, e-mails, integrações, campos específicos), mas ainda não executa implementações ou manutenções diretamente.' FROM skills s, roles r WHERE s.name = 'API Cadastro' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Possui conhecimento prático da API Cadastro, realizando implementações e manutenções com autonomia moderada. É capaz de configurar e testar autenticação via Bearer Token entendendo a obrigatoriedade de que todas as chamadas partam de um Parceiro, utilizando client e secret válidos para obtenção do IdContrato. Executar a jornada completa de ativação de empresa via API. Implementa e valida chamadas garantindo retorno adequado no formato esperado. Capaz de criar e/ou manter endpoints seguindo o padrão do repositório ndd-configuracao. Compreende o cadastro e validações de documentos fiscais (CTe, MDFe, NFe, NFSe – emissão e recebimento). Consegue identificar e corrigir erros comuns de autenticação, integração ou inconsistência de dados e é capaz de validar corretamente vínculo com Parceiro e captura de IdContrato. Atua na sustentação da API, realizando manutenção de nível básico a intermediário, seguindo padrões estabelecidos e boas práticas da equipe.' FROM skills s, roles r WHERE s.name = 'API Cadastro' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Possui conhecimento avançado e visão sistêmica da API Cadastro, atuando como referência técnica na solução. É capaz de definir e evoluir padrões arquiteturais da API. Projetar melhorias estruturais visando escalabilidade, segurança e performance. Atuar em decisões técnicas sobre autenticação, versionamento e integração entre APIs. Otimizar consultas com dapper e estrutura de dados na base Central_frontConfig. Analisar impactos de mudanças na jornada de ativação de empresas. Atuar preventivamente em segurança (tokens, autorização, validação de dados). onhecimento para análise de incidentes críticos. Apoiar integrações complexas com parceiros e novos fluxos de ativação. Treinar e desenvolver outros profissionais na utilização e evolução da API. Atua estrategicamente na evolução da API Cadastro, garantindo robustez, governança técnica, alinhamento arquitetural e sustentabilidade da solução no longo prazo. Capaz de planejar e criar novos cadastros para documentos que ainda não fazem parte da API Cadastro.' FROM skills s, roles r WHERE s.name = 'API Cadastro' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
