INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Analisa PRs seguindo o desenho de solução feito pelo time de arquitetura, podendo sugerir melhorias de performance e qualidade de código dos PRs' FROM skills s, roles r WHERE s.name = 'Avaliação de PR (Políticas de PR)' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Revisa código com visão sistêmica, avaliando a profundidade técnica e responsabilidade sobre o impacto no produto e na empresa. Ele não se limita a verificar se a funcionalidade “funciona”, mas avalia se a solução é sustentável, coerente com a arquitetura, alinhada às regras de negócio e segura para produção.' FROM skills s, roles r WHERE s.name = 'Avaliação de PR (Políticas de PR)' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
