INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Possui compreensão básica do motor de bilhetagem e autonomia para adicionar novos documentos e tipos de eventos ao processo de medição. Conhece as distinções entre os fluxos de faturamento por licença e por volumetria, garantindo a correta categorização dos eventos. É capaz de extrair relatórios simples de consumo, identificando a distribuição de tipos de documentos processados em determinados períodos para conferência de dados.' FROM skills s, roles r WHERE s.name = 'Bilhetagem' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Domina a estrutura de dados do sistema de bilhetagem, sendo capaz de realizar manutenção avançada diretamente via banco de dados. Consegue rastrear o ciclo de vida de um bilhete, identificar falhas de processamento, divergências de contagem ou problemas de integração entre módulos. Atua na investigação de causas raiz para incidentes de faturamento, garantindo que as regras de negócio sejam aplicadas corretamente aos registros brutos.' FROM skills s, roles r WHERE s.name = 'Bilhetagem' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'É a autoridade técnica no fluxo de faturamento, detendo o domínio sobre as rotinas de reprocessamento de bilhetes e correção de massa de dados. Possui visão estratégica para orquestrar recuperações de bilhetagem sem gerar duplicidade ou impactos financeiros. Atua na instrução e formação do time, definindo os procedimentos padrão para o processamento de cada etapa e garantindo a resiliência e a auditabilidade de todo o ecossistema de bilhetagem.' FROM skills s, roles r WHERE s.name = 'Bilhetagem' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Possui compreensão básica do motor de bilhetagem e autonomia para adicionar novos documentos e tipos de eventos ao processo de medição. Conhece as distinções entre os fluxos de faturamento por licença e por volumetria, garantindo a correta categorização dos eventos. É capaz de extrair relatórios simples de consumo, identificando a distribuição de tipos de documentos processados em determinados períodos para conferência de dados.' FROM skills s, roles r WHERE s.name = 'Bilhetagem' AND r.name = 'Qualidade' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
