INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Domina os fluxos operacionais de contingência para os diversos modelos de documentos, incluindo NFCom e processos que tramitam pelo host de transformação e retorno. Compreende as diferenças entre o acionamento manual e automático e sabe operar os principais protocolos de contingência do mercado, como EPEC, FS-DA e SVC (Sefaz Virtual de Contingência).' FROM skills s, roles r WHERE s.name = 'Contigencia em Geral' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Possui capacidade técnica para realizar manutenções corretivas e evolutivas nos componentes de contingência. Consegue identificar falhas na detecção automática de problemas e ajustar as regras de transição entre o fluxo normal e o de contingência. Atua na resolução de problemas complexos de sincronismo de retorno e tratamento de rejeições específicas de documentos emitidos em regime especial, garantindo a integridade fiscal e a conciliação correta dos documentos após a normalização do ambiente.' FROM skills s, roles r WHERE s.name = 'Contigencia em Geral' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'É a autoridade máxima em estratégias de alta disponibilidade e continuidade de negócio no que tange à emissão fiscal. Possui visão crítica para propor melhorias estruturais que reduzam o tempo de resposta em casos de falha. Define os padrões de governança para o acionamento de contingências, orienta o time em cenários de crise e possui domínio profundo sobre as particularidades regulatórias de cada estado/modelo. Atua na arquitetura de soluções que previnem a perda de documentos e garante que o conhecimento técnico seja disseminado para elevar a resiliência operacional da organização.' FROM skills s, roles r WHERE s.name = 'Contigencia em Geral' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
