INSERT INTO skill_expectations (skill_id, role_id, grade_id, expected_level, is_required) SELECT s.id, r.id, g.id, 'OURO', TRUE FROM skills s, roles r, grades g WHERE s.name = 'Fluxo de Importação de Documentos para DEV' AND r.name = 'Desenvolvedor Backend' AND g.name = 'SENIOR' ON CONFLICT (skill_id, role_id, grade_id) DO UPDATE SET expected_level = EXCLUDED.expected_level, is_required = EXCLUDED.is_required;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'O desenvolvedor nível Bronze possui entendimento funcional das principais etapas do fluxo de importação de documentos, conseguindo identificar onde cada parte é executada no código e reconhecendo os módulos envolvidos e suas responsabilidades básicas. Aplica regras de negócio já definidas quando especificadas e realiza correções pontuais de bugs com apoio técnico.
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'O desenvolvedor nível Prata compreende o fluxo de importação ponta a ponta, incluindo integrações, validações, dependências entre módulos e regras de negócio complexas. Atua de forma autônoma na correção de bugs, conduz análises de causa raiz e implementa funcionalidades completas avaliando impactos no fluxo como um todo.
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'O desenvolvedor nível Ouro possui visão sistêmica e aprofundada de todo o fluxo de importação de documentos, abrangendo arquitetura, integrações externas, regras críticas, performance, escalabilidade e riscos operacionais. Domina as interações entre módulos e antecipa impactos técnicos antes da implementação de mudanças.
