INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Foi treinado ou estudou a funcionalidade de Herança de Configurações no portal e compreende seu objetivo de promover padronização e uniformidade entre Grupo, Matriz e Filial. Conhece os conceitos gerais, a herança de Grupo e Matriz, o processo de Customização individual quando herança estiver desmarcada, como funciona a Replicação automática e onde ocorre o processamento, também possui entendimento conceitual do fluxo, mas ainda não atua diretamente na implementação ou manutenção.' FROM skills s, roles r WHERE s.name = 'Herança por Empresa e Grupo Empresa' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Possui domínio prático da jornada de herança dentro do portal, seja para grupo empresa ou matriz, atuando tanto na camada funcional quanto técnica (backend e mensageria), garantindo a implementação conforme o desenho arquitetural e se sente confortável para participar de desições de arquitetura e performance. Atua na sustentação da funcionalidade, resolvendo problemas de nível básico a intermediário.' FROM skills s, roles r WHERE s.name = 'Herança por Empresa e Grupo Empresa' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Possui visão sistêmica da arquitetura de herança, incluindo portal, banco, mensageria, cache e impactos organizacionais. É referência técnica na evolução e governança da funcionalidade. Possui capacidade para auxiliar na arquitetura e performance, de definir com o time de arquitetura a estratégia de herança escalável para grandes volumes de empresas. Compreende o impacto da replicação em massa, atualizações simultâneas e garante que as replicações sejam realizadas corretamente. Avalia os riscos e conflitos, definindo estratégias seguras de rooback. Atua como referência técnica para squads e arquitetura, garante que a funcionalidade de herança seja escalável, segura e auditável.' FROM skills s, roles r WHERE s.name = 'Herança por Empresa e Grupo Empresa' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
