INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Compreende o fluxo macro de comunicação entre a camada Fiscal e o Front-end, identificando as etapas e os componentes por onde os dados trafegam. Possui domínio operacional sobre as funções de ciclo de vida e atualização, sabendo manipular as interfaces do Front-end para disparar ações destinadas ao Fiscal. É capaz de realizar chamadas técnicas via API Connector para processos críticos, como execução de ações do Fiscal, coleta de logs, download de pacotes e monitoramento de status, garantindo a execução das rotinas operacionais básicas.' FROM skills s, roles r WHERE s.name = 'Host Settings' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Domina as responsabilidades intrínsecas do Host Settings dentro da arquitetura, compreendendo seu papel como orquestrador de configurações e estados. Possui autonomia para realizar manutenções no componente, identificar inconsistências de configuração e garantir que suas obrigações no fluxo (como a distribuição de parâmetros e diretrizes de execução) sejam cumpridas. É capaz de realizar o troubleshooting de comunicações interrompidas ou configurações mal aplicadas que impactem a sincronia entre as pontas.' FROM skills s, roles r WHERE s.name = 'Host Settings' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Atua com visão arquitetural sobre o Host Settings, sendo capaz de propor e implementar melhorias no fluxo de configuração e atualização para torná-lo mais resiliente e performático. É a referência técnica para o time, possuindo total capacidade de transmitir o conhecimento sobre o funcionamento interno do componente e seu impacto no ecossistema. Define padrões de segurança e escalabilidade para a gestão de hosts e orienta as decisões estratégicas sobre como as definições de ambiente devem evoluir para suportar novos modelos de negócio.' FROM skills s, roles r WHERE s.name = 'Host Settings' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Compreende o fluxo macro de comunicação entre a camada Fiscal e o Front-end, identificando as etapas e os componentes por onde os dados trafegam. Possui domínio operacional sobre as funções de ciclo de vida e atualização, sabendo manipular as interfaces do Front-end para disparar ações destinadas ao Fiscal. É capaz de realizar chamadas técnicas via API Connector para processos críticos, como execução de ações do Fiscal, coleta de logs, download de pacotes e monitoramento de status, garantindo a execução das rotinas operacionais básicas.' FROM skills s, roles r WHERE s.name = 'Host Settings' AND r.name = 'Qualidade' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
