INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Possui conhecimento operacional sobre o ecossistema de APIs e conectores da organização, incluindo API Conector, NGProxy e WS Integração. É capaz de realizar chamadas técnicas via ferramentas como Postman, consumindo documentação para realizar a captura e consulta de documentos. Compreende a interação com os módulos Fiscal e Integrator, além de entender o fluxo de rastreio e integração com sistemas legados e a comunicação de novos modelos (como NFCom e NF3e) com o Front-end. Domina os protocolos de comunicação e as divergências entre APIs e camadas fiscais, além de aplicar corretamente as regras de licenciamento e permissionamento dentro do fluxo de integração.' FROM skills s, roles r WHERE s.name = 'Integrações em Geral' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Demonstra autonomia para realizar o entendimento de problemas do fluxo de integração, sendo capaz de identificar gargalos e falhas de comunicação entre os módulos. Possui capacidade técnica para realizar manutenções e evoluções no código-fonte, seguindo rigorosamente os padrões de desenvolvimento estabelecidos. Consegue construir consultas complexas para busca de documentos e otimização de performance, garantindo que a troca de dados entre o Integrator e os sistemas fiscais ocorra de forma íntegra e eficiente.' FROM skills s, roles r WHERE s.name = 'Integrações em Geral' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Atua com visão sistêmica sobre toda a arquitetura de integração, sendo capaz de identificar oportunidades de melhoria estrutural nos processos para aumentar a resiliência e a escalabilidade. É a autoridade técnica para definir e orientar o time sobre os padrões de design de APIs, segurança de protocolos e fluxos de dados entre o legado e as novas frentes. Atua como mentor, garantindo que a evolução do ecossistema de integrações (seja via NGProxy ou novos conectores) siga as melhores práticas de mercado e os requisitos de negócio da organização.' FROM skills s, roles r WHERE s.name = 'Integrações em Geral' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
