INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Backend: Compreende o fluxo macro de entrada de documentos e suas diversas origens (EDI, OCR, EmailEntry e DFe). Identifica o papel de cada ator no ciclo de vida de uma nota fiscal (Emitente, Destinatário, Transportador) e possui autonomia para localizar documentos diretamente no banco de dados. É capaz de realizar buscas manuais de documentos e executar o envio ou reenvio para processamento, garantindo que a entrada de dados no ecossistema fiscal ocorra conforme os procedimentos operacionais padrão.
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Backend: Domina a lógica de recepção automática e os mecanismos de captura de documentos, sendo capaz de realizar manutenções corretivas e ajustes nos serviços de importação. Compreende profundamente os vínculos dos documentos (como associações entre CT-e e NF-e) e as regras de negócio aplicadas na triagem inicial. Atua na resolução de problemas de integração entre os canais de entrada e o motor fiscal, garantindo a integridade dos metadados extraídos via OCR ou processados via EDI.
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Backend: É a autoridade técnica na arquitetura de recepção de documentos, possuindo visão estratégica para otimizar o desempenho do processamento de altos volumes de dados. Atua na definição de padrões de captura e reconhecimento, propondo melhorias na acurácia do OCR e na resiliência dos fluxos de EmailEntry e DFe. É capaz de orientar o time sobre a complexidade das regras fiscais de recepção, gerenciar exceções críticas de importação e liderar a evolução tecnológica dos componentes para garantir que a entrada de dados seja escalável e à prova de falhas.
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Backend: Compreende o fluxo macro de entrada de documentos e suas diversas origens (EDI, OCR, EmailEntry e DFe). Identifica o papel de cada ator no ciclo de vida de uma nota fiscal (Emitente, Destinatário, Transportador) e possui autonomia para localizar documentos diretamente no banco de dados. É capaz de realizar buscas manuais de documentos e executar o envio ou reenvio para processamento, garantindo que a entrada de dados no ecossistema fiscal ocorra conforme os procedimentos operacionais padrão.
