INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Conhece os diferentes tipos de transformações (Código/DLL, XSLT e Connectus) e atua no suporte e manutenção de mapeamentos existentes. É capaz de realizar alterações estruturais simples, como renomear ou adicionar tags, e ajustar regras básicas no Connectus. Possui autonomia para realizar validações técnicas, montar arquivos XML ou JSON a partir de objetos e manipular documentos utilizando XDocument, XmlDocument ou variantes. Utiliza o componente de XSLT para execuções rotineiras, criando testes automatizados conforme os padrões estabelecidos e garantindo o funcionamento das transformações sob supervisão ou seguindo documentação interna.' FROM skills s, roles r WHERE s.name = 'Transformações' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Domina a operação interna do componente XSLT, sendo capaz de manipular o código-fonte, estruturar testes automatizados complexos e gerenciar o comportamento do componente. Atua na criação de novos mapeamentos tanto no Connectus quanto em XSLT, desenvolvendo regras compartilhadas para otimizar o reaproveitamento de código. Possui maturidade para dar manutenção na DLL de NFSe e implementar regras de negócio de alta complexidade no Connectus. Identifica falhas de lógica em transformações vigentes e propõe ajustes que garantam a integridade dos dados entre diferentes formatos e protocolos.' FROM skills s, roles r WHERE s.name = 'Transformações' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'É a referência técnica em estratégias de transformação, possuindo visão crítica sobre a eficiência, limitações técnicas e custos computacionais de cada abordagem (XSLT vs. DLL vs. Connectus). Domina arquiteturas complexas, como a implementação de loops em arquivos posicionais (TXT) e pipelines no Connectus que referenciam o documento de forma integral. Detém o conhecimento profundo sobre o ciclo de build e a componentização das soluções de XSLT e NFSe. Além de definir padrões de desenvolvimento e governança para as transformações da organização, tem capacidade de treinar o time, disseminar boas práticas de performance e conduzir a evolução técnica do ecossistema de integração.' FROM skills s, roles r WHERE s.name = 'Transformações' AND r.name = 'Desenvolvedor Backend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
