INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'O desenvolvedor nível Bronze possui entendimento funcional da tela e dos principais fluxos do host volumetria, conseguindo identificar onde cada parte é executada no código e suas responsabilidades básicas. Aplica regras de negócio já definidas quando especificadas e realiza correções pontuais de bugs com apoio técnico. Consegue realizar debug em cenários conhecidos, mas necessita suporte para análises mais complexas ou investigações aprofundadas. Ainda depende de acompanhamento técnico em demandas de maior complexidade, atuando sob direcionamento e contribuindo conforme escopo previamente delimitado.' FROM skills s, roles r WHERE s.name = 'Volumetria' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'O desenvolvedor nível Prata compreende o fluxo do host ponta a ponta, as tabelas envolvidas para gestão da volumetria, suas validações, as dependências entre módulos e regras de negócio mais complexas. Atua de forma autônoma na correção de bugs, conduz análises de causa raiz e implementa funcionalidades completas avaliando impactos no fluxo como um todo. Entende claramente responsabilidades, contratos e dependências entre módulos, diagnostica problemas técnicos de forma independente, inclusive em cenários de inconsistência de dados e recálculo de volumetria. Possui autonomia técnica para sustentar o módulo, colabora ativamente com o time e propõe melhorias incrementais visando qualidade e manutenção do fluxo.' FROM skills s, roles r WHERE s.name = 'Volumetria' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'O desenvolvedor nível Ouro possui visão sistêmica e aprofundada de todo o fluxo de volumetria, apresentação, cálculo e estrutura de banco, abrangendo arquitetura, regras críticas, performance, escalabilidade e riscos operacionais. Domina as interações entre módulos e antecipa impactos técnicos antes da implementação de mudanças. Atua em incidentes críticos e problemas complexos, inclusive estruturais, conduz análises avançadas de diagnóstico e define abordagens técnicas para novas implementações. Participa da definição e evolução de regras junto ao negócio, revisa e estabelece padrões técnicos e define estratégias de qualidade e testes em servidor. É referência técnica do módulo, apoia o desenvolvimento de outros profissionais, conduz decisões técnicas relevantes e propõe melhorias estruturais que aumentem robustez, manutenibilidade e eficiência do fluxo.' FROM skills s, roles r WHERE s.name = 'Volumetria' AND r.name = 'Desenvolvedor Frontend' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
