INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Foi treinado ou estudos as ferramentas e aplica no dia a dia seguindo padrões internos e documentações oficiais. Consegue instalar, configurar e operar Windows Server (recursos Server Management), SQL Server (Logs, limpezas e manutenção basica), IIS e certificados digitais com apoio de documentação interna. Executa tarefas operacionais como criação de sites no IIS, configuração básica de pools de aplicação, liberação e verificação de portas de rede, instalação de certificados (NDD assinatura e NDD DNS), permissões no Windows, recursos necessários para funcionamento da Plataforma no Windows. Analisa e resolve problemas de nível basico a intermediário, seguindo procedimentos já definidos e boas práticas estabelecidas pela equipe. Atua com segurança operacional, executando conforme orientações e padrões vigentes.' FROM skills s, roles r WHERE s.name = 'Ferramentas base para Testes (Windows Server / SQL / IIS / Certificados)' AND r.name = 'Qualidade' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Configura ambientes do zero com autonomia, baseando-se em documentações oficiais e boas práticas de mercado. Possui conhecimento pleno de execução autodidata, compreendendo os conceitos técnicos por trás das configurações realizadas. Realiza instalação, hardening(processo de fortalecer a segurança de infraestrutura) e manutenção de Windows Server, SQL Server e IIS, incluindo configuração de segurança, performance, certificados SSL/TLS, bindings, autenticação, permissões, tuning de banco e troubleshooting(diagnóstico e resolução de problemas) avançado. Entende os motivos técnicos das decisões atuais de arquitetura e consegue explicar diferenças entre versões, modos de configuração e necessidades específicas do ambiente. Identifica problemas, propõe e implementa melhorias estruturais, atuando de forma preventiva e evolutiva.' FROM skills s, roles r WHERE s.name = 'Ferramentas base para Testes (Windows Server / SQL / IIS / Certificados)' AND r.name = 'Qualidade' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Possui conhecimento avançado e visão estratégica sobre a stack Microsoft, atuando como referência técnica. Contribui nas tomadas de decisão em nível de arquitetura, integração com times de Arquitetura e DevOps e definição de padrões organizacionais. Avalia evoluções tecnológicas, impactos de upgrade, mudanças de versão, estratégias de alta disponibilidade, segurança avançada e conformidade. Treina e desenvolve outros profissionais, disseminando boas práticas e conceitos de mercado relacionados a infraestrutura, banco de dados, segurança e publicação de aplicações. Atua com visão sistêmica, garantindo performance, escalabilidade, segurança e alinhamento com as melhores práticas do mercado.' FROM skills s, roles r WHERE s.name = 'Ferramentas base para Testes (Windows Server / SQL / IIS / Certificados)' AND r.name = 'Qualidade' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
