INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'BRONZE', 'Analisa portas em uso e consegue identificar se o problema está no servidor, na rede ou na aplicação (DEV). Entende conceitos básicos de WAF e CSP, sabendo qual seu papel e onde são configurados. Consegue validar bloqueios simples de firewall e conectividade. Atua de forma crítica ao conversar com áreas de apoio, como Infraestrutura, conseguindo direcionar problemas e alinhar possíveis soluções com base em evidências técnicas.' FROM skills s, roles r WHERE s.name = 'Rede para Testes (Firewall / DNS / WAF / VPN / Windows / CSP)' AND r.name = 'Qualidade' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'PRATA', 'Entende configurações mais avançadas de rede relacionadas a IIS e publicação de aplicações. Compreende a estrutura de rede entre ambientes locais e nuvem, incluindo camadas, fluxos de comunicação e autenticações necessárias. Domina conceitos e configurações de WAF e CSP, aplicando boas práticas de segurança e avaliando impactos de módulos locais ou externos, suas necessidades e possíveis vulnerabilidades. Participa ativamente na definição de caminhos técnicos junto a DevOps e Arquitetura. Assume discussões mais complexas com times de apoio (Infra), conduzindo análises e propondo soluções consistentes.' FROM skills s, roles r WHERE s.name = 'Rede para Testes (Firewall / DNS / WAF / VPN / Windows / CSP)' AND r.name = 'Qualidade' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
INSERT INTO skill_descriptions (skill_id, role_id, level, description) SELECT s.id, r.id, 'OURO', 'Domina padrões de mercado relacionados a rede e segurança para publicação de aplicações. Analisa criticamente a forma como os produtos estão configurados e publicados, propondo projetos estruturados de melhoria em arquitetura, segurança e exposição de serviços. Atua como referência técnica no assunto para o time de Testes, capacitando profissionais e elevando o nível técnico da equipe em temas de rede e segurança aplicada.' FROM skills s, roles r WHERE s.name = 'Rede para Testes (Firewall / DNS / WAF / VPN / Windows / CSP)' AND r.name = 'Qualidade' ON CONFLICT (skill_id, role_id, level) DO UPDATE SET description = EXCLUDED.description;
